import React, { useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

const WelcomePage = () => {
  const [stage, setStage] = useState('brain-trace');

  useEffect(() => {
    // 1. Brain trace (2.5s) → 2. CC draws (1.5s) → 3. Main Site
    const timer1 = setTimeout(() => setStage('cc-draw'), 2500);
    const timer2 = setTimeout(() => setStage('main'), 4000);
    return () => {
      clearTimeout(timer1);
      clearTimeout(timer2);
    };
  }, []);

  const featuresRow1 = [
    { title: 'Course Curator', desc: 'AI picks the single best video for your concept.' },
    { title: 'Quiz Generator', desc: 'Adaptive questions with explanations.' },
    { title: 'Notes Generator', desc: 'Live summaries and key concepts.' },
    { title: 'Course Curator', desc: 'AI picks the single best video.' },
    { title: 'Quiz Generator', desc: 'Adaptive questions.' },
  ];

  const featuresRow2 = [
    { title: 'Revision Scheduler', desc: 'Smart reminders for better retention.' },
    { title: 'Update Acknowledger', desc: 'Stay updated within 48 hours.' },
    { title: 'Premium Features', desc: 'Unlock full learning power.' },
    { title: 'Revision Scheduler', desc: 'Smart reminders.' },
    { title: 'Update Acknowledger', desc: 'Stay updated.' },
  ];

  return (
    <div className="min-h-screen bg-white text-[#0B3954] overflow-x-hidden font-serif">

      {/* 1. ANIMATIONS: BRAIN + CC + MAIN */}
      <AnimatePresence mode="wait">

        {/* STAGE 1: NEURAL NETWORK BRAIN TRACE */}
        {stage === 'brain-trace' && (
          <motion.div
            key="brain-trace"
            className="fixed inset-0 flex items-center justify-center bg-white z-50"
            exit={{ opacity: 0, scale: 1.1 }}
            transition={{ duration: 0.5 }}
          >
            <svg
              width="200"
              height="200"
              viewBox="0 0 200 200"
              className="w-64 h-64"
            >
              {/* Neuron / network nodes */}
              <circle cx="100" cy="100" r="12" fill="#0B3954" />
              <circle cx="60" cy="70" r="8" fill="#0B3954" />
              <circle cx="140" cy="70" r="8" fill="#0B3954" />
              <circle cx="65" cy="130" r="8" fill="#0B3954" />
              <circle cx="135" cy="130" r="8" fill="#0B3954" />

              {/* Neural connections (animated paths) */}
              <motion.path
                d="M 100 100 L 60 70"
                stroke="#0B3954"
                strokeWidth="4"
                fill="none"
                initial={{ pathLength: 0 }}
                animate={{ pathLength: 1 }}
                transition={{ duration: 0.8, ease: "easeInOut" }}
              />
              <motion.path
                d="M 100 100 L 140 70"
                stroke="#0B3954"
                strokeWidth="4"
                fill="none"
                initial={{ pathLength: 0 }}
                animate={{ pathLength: 1 }}
                transition={{ duration: 0.8, ease: "easeInOut", delay: 0.2 }}
              />
              <motion.path
                d="M 100 100 L 65 130"
                stroke="#0B3954"
                strokeWidth="4"
                fill="none"
                initial={{ pathLength: 0 }}
                animate={{ pathLength: 1 }}
                transition={{ duration: 0.8, ease: "easeInOut", delay: 0.4 }}
              />
              <motion.path
                d="M 100 100 L 135 130"
                stroke="#0B3954"
                strokeWidth="4"
                fill="none"
                initial={{ pathLength: 0 }}
                animate={{ pathLength: 1 }}
                transition={{ duration: 0.8, ease: "easeInOut", delay: 0.6 }}
              />

              {/* Arc around the brain to give a “brain” outline */}
              <motion.path
                d="M 100 40 C 60 40, 40 100, 60 160 C 80 200, 120 200, 140 160 C 160 100, 140 40, 100 40"
                stroke="#0B3954"
                strokeWidth="6"
                fill="none"
                initial={{ pathLength: 0 }}
                animate={{ pathLength: 1 }}
                transition={{ duration: 1.5, ease: "easeInOut", delay: 0.2 }}
              />
            </svg>

            {/* Optional: small “Play” button that pops in after the brain is done */}
            <AnimatePresence>
              <motion.div
                initial={{ opacity: 0, scale: 0.8 }}
                animate={{ opacity: 1, scale: 1 }}
                exit={{ opacity: 0 }}
                transition={{ delay: 1.8, duration: 0.4 }}
                className="absolute -bottom-24 text-center"
              >
                <button
                  className="px-8 py-3 bg-[#0B3954] text-white rounded-full text-sm font-bold tracking-[0.1em] hover:scale-105 active:scale-95 transition-transform"
                  onClick={() => setStage('cc-draw')}
                  style={{ border: '2px solid white' }}
                >
                  Play • Start
                </button>
              </motion.div>
            </AnimatePresence>
          </motion.div>
        )}

        {/* STAGE 2: CC DRAW */}
        {stage === 'cc-draw' && (
          <motion.div
            key="cc-stage"
            className="fixed inset-0 flex items-center justify-center bg-white z-50"
            exit={{ opacity: 0 }}
          >
            <svg width="400" height="200" viewBox="0 0 200 100">
              <motion.path
                d="M60 30 C 20 30, 20 70, 60 70"
                fill="none"
                stroke="#0B3954"
                strokeWidth="8"
                strokeLinecap="round"
                initial={{ pathLength: 0 }}
                animate={{ pathLength: 1 }}
                transition={{ duration: 1, ease: "easeInOut" }}
              />
              <motion.path
                d="M140 30 C 100 30, 100 70, 140 70"
                fill="none"
                stroke="#0B3954"
                strokeWidth="8"
                strokeLinecap="round"
                initial={{ pathLength: 0 }}
                animate={{ pathLength: 1 }}
                transition={{ duration: 1, ease: "easeInOut", delay: 0.2 }}
              />
            </svg>
          </motion.div>
        )}
      </AnimatePresence>

